import{_ as t,o as i,c as a,a0 as n}from"./chunks/framework.B_R3rS_4.js";const s="/docs/reconstruction_preview.jpg",r="/docs/latent_map_preview.png",m=JSON.parse('{"title":"Case Study: Neural RTI Training and Run Evaluation","description":"","frontmatter":{},"headers":[],"relativePath":"technical/case-study.md","filePath":"technical/case-study.md"}'),o={name:"technical/case-study.md"};function l(d,e,h,c,g,p){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="case-study-neural-rti-training-and-run-evaluation" tabindex="-1">Case Study: Neural RTI Training and Run Evaluation <a class="header-anchor" href="#case-study-neural-rti-training-and-run-evaluation" aria-label="Permalink to &quot;Case Study: Neural RTI Training and Run Evaluation&quot;">​</a></h1><p>This case study analyzes the performance, compression efficiency, and visual rendering results of our Neural RTI training run completed on <strong>July 3, 2026</strong>, using the high-resolution RTI dataset <code>DEMO-2024-SEAL-001</code>.</p><hr><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><p>The training run was executed at full resolution (<code>--resize 0</code>), processing the <strong>4096x3072</strong> resolution image. The pipeline successfully optimized a <strong>4-dimensional latent grid</strong> at every pixel location along with a <strong>shared Decoder MLP</strong> to model the continuous hemispherical reflectance function.</p><p>The run achieved <strong>exceptional fidelity and generalization</strong>, showing no signs of overfitting to the training light directions. Additionally, it achieved a substantial <strong>6x compression ratio</strong> of the raw coefficient files.</p><hr><h2 id="_2-dataset-profile-1921-7-dk-2-8256" tabindex="-1">2. Dataset Profile: <code>DEMO-2024-SEAL-001</code> <a class="header-anchor" href="#_2-dataset-profile-1921-7-dk-2-8256" aria-label="Permalink to &quot;2. Dataset Profile: `DEMO-2024-SEAL-001`&quot;">​</a></h2><p>The test subject is a high-resolution RTI dataset of a historical artifact (likely a clay sealing).</p><ul><li><strong>Format (Original):</strong> Hemispherical Harmonics (HSH, Type 1)</li><li><strong>Resolution:</strong> 4096 x 3072 pixels (~45.4 Megapixels)</li><li><strong>Original File Size (HSH):</strong> <strong>18.5 MB</strong></li><li><strong>Active Area:</strong> Padded to 8192 x 8192 for quadtree tiling.</li></ul><hr><h2 id="_3-reconstructed-previews" tabindex="-1">3. Reconstructed Previews <a class="header-anchor" href="#_3-reconstructed-previews" aria-label="Permalink to &quot;3. Reconstructed Previews&quot;">​</a></h2><p>Below are the 800px downsampled visual previews generated from our optimized representation.</p><h3 id="original-reconstruction-light-from-above" tabindex="-1">Original Reconstruction (Light from Above) <a class="header-anchor" href="#original-reconstruction-light-from-above" aria-label="Permalink to &quot;Original Reconstruction (Light from Above)&quot;">​</a></h3><p>This preview is rendered by passing the downsampled latent map through the Decoder MLP in PyTorch at light direction [0, 0, 1]:</p><p><img src="'+s+'" alt="Reconstructed Preview"></p><h3 id="raw-latent-map" tabindex="-1">Raw Latent Map <a class="header-anchor" href="#raw-latent-map" aria-label="Permalink to &quot;Raw Latent Map&quot;">​</a></h3><p>This is the corresponding 4D latent representation (visualized as an RGB image) learned by the network:</p><p><img src="'+r+`" alt="Latent Map Preview"></p><hr><h2 id="_4-quantitative-metric-performance" tabindex="-1">4. Quantitative Metric Performance <a class="header-anchor" href="#_4-quantitative-metric-performance" aria-label="Permalink to &quot;4. Quantitative Metric Performance&quot;">​</a></h2><p>A sample of <strong>1,000,000 pixels</strong> was evaluated across all training lights (64 lights) and a validation set of unseen light directions (10 random lights on the hemisphere).</p><table tabindex="0"><thead><tr><th style="text-align:left;">Metric</th><th style="text-align:left;">Training Lights (64 directions)</th><th style="text-align:left;">Validation Lights (10 unseen directions)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Mean Squared Error (MSE)</strong></td><td style="text-align:left;"><code>0.0006440</code></td><td style="text-align:left;"><code>0.0006439</code></td></tr><tr><td style="text-align:left;"><strong>Peak Signal-to-Noise Ratio (PSNR)</strong></td><td style="text-align:left;"><strong>31.91 dB</strong></td><td style="text-align:left;"><strong>31.91 dB</strong></td></tr><tr><td style="text-align:left;"><strong>Root Mean Squared Error (RMSE)</strong></td><td style="text-align:left;"><code>0.02537</code></td><td style="text-align:left;"><code>0.02537</code></td></tr><tr><td style="text-align:left;"><strong>Avg. 8-Bit Pixel Intensity Error</strong></td><td style="text-align:left;"><strong>~6.47 levels</strong> (out of 255)</td><td style="text-align:left;"><strong>~6.47 levels</strong> (out of 255)</td></tr></tbody></table><h3 id="error-consistency" tabindex="-1">Error Consistency <a class="header-anchor" href="#error-consistency" aria-label="Permalink to &quot;Error Consistency&quot;">​</a></h3><ul><li><strong>Minimum Train MSE (Best Light Direction):</strong> <code>0.0004183</code> (~33.78 dB PSNR)</li><li><strong>Maximum Train MSE (Worst Light Direction):</strong> <code>0.0010113</code> (~29.95 dB PSNR)</li></ul><hr><h2 id="_5-core-findings-learnings" tabindex="-1">5. Core Findings &amp; Learnings <a class="header-anchor" href="#_5-core-findings-learnings" aria-label="Permalink to &quot;5. Core Findings &amp; Learnings&quot;">​</a></h2><h3 id="_1-flawless-generalization" tabindex="-1">1. Flawless Generalization <a class="header-anchor" href="#_1-flawless-generalization" aria-label="Permalink to &quot;1. Flawless Generalization&quot;">​</a></h3><p>The most outstanding feature of this run is that the <strong>Validation PSNR matches the Training PSNR exactly at 31.91 dB</strong>.</p><ul><li>Because the decoder is conditioned on physical 3D light vectors <code>[x, y, z]</code> on the hemisphere, the MLP learns the continuous light response function rather than memorizing discrete directions.</li><li>Interpolating new, unseen light directions in a web viewer will produce smooth, photorealistic shading transitions without artifacts.</li></ul><h3 id="_2-high-fidelity-reconstruction" tabindex="-1">2. High-Fidelity Reconstruction <a class="header-anchor" href="#_2-high-fidelity-reconstruction" aria-label="Permalink to &quot;2. High-Fidelity Reconstruction&quot;">​</a></h3><p>A PSNR of <strong>31.91 dB</strong> is a high-quality reconstruction.</p><ul><li>In human perception, a PSNR above 30 dB makes the reconstructed image virtually indistinguishable from the original HSH representation.</li><li>The average per-channel intensity deviation is only <strong>6.47 levels</strong> on an 8-bit scale <code>[0, 255]</code>.</li></ul><h3 id="_3-substantial-data-compression" tabindex="-1">3. Substantial Data Compression <a class="header-anchor" href="#_3-substantial-data-compression" aria-label="Permalink to &quot;3. Substantial Data Compression&quot;">​</a></h3><p>The neural representation yields significant storage and bandwidth savings compared to raw HSH coefficients:</p><ul><li><strong>Original HSH (.rti) size:</strong> <strong>18.5 MB</strong></li><li><strong>Neural Latent Map (<code>latent_map.png</code>):</strong> <strong>90.9 MB</strong></li><li><strong>Decoder MLP (<code>decoder_weights.json</code>):</strong> <strong>13 KB</strong></li><li><strong>Total Neural size:</strong> <strong>~90.9 MB</strong> (6.0x compression / <strong>83.3% space reduction</strong>)</li></ul><p>For web-based sharing databases (like <code>rtiDb</code>), this compression is a game-changer. It permits high-speed page loads and reduces HTTP Range Request data transfers by a factor of 6.</p><hr><h2 id="_6-web-viewer-webgl-rendering-implementation" tabindex="-1">6. Web Viewer &amp; WebGL Rendering Implementation <a class="header-anchor" href="#_6-web-viewer-webgl-rendering-implementation" aria-label="Permalink to &quot;6. Web Viewer &amp; WebGL Rendering Implementation&quot;">​</a></h2><p>Because the decoder MLP is extremely lightweight (3 linear layers with 16 hidden units, totaling only <strong>448 parameters</strong>), it is ideal for real-time client-side rendering.</p><ol><li><strong>Latent Map Loading:</strong> The <code>latent_map.png</code> is loaded in the browser as a standard RGBA 8-bit texture.</li><li><strong>MLP Execution:</strong> The 13 KB <code>decoder_weights.json</code> is sent to a WebGL shader. The shader executes the MLP feed-forward pass per-pixel inside the fragment shader:<div class="language-glsl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">glsl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Signature concept for the WebGL fragment shader</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vec4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> latent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> texture2D</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(u_latentMap, v_texCoord);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vec3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> light_dir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> u_lightDirection;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">vec3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> color </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> evaluate_mlp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(latent, light_dir, u_weights);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">gl_FragColor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> vec4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(color, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div></li><li><strong>Bandwidth Savings:</strong> Instead of streaming 545 MB of binary coefficients over the network, only 90.9 MB needs to be transferred to the browser.</li></ol>`,41)])])}const f=t(o,[["render",l]]);export{m as __pageData,f as default};
